-- Garantir l'existence des 4 modules, réassocier les questions orphelines,
-- et réinsérer les 106 questions complémentaires (au cas où la migration 300000 a échoué)

-- 1. Créer les modules manquants s'ils n'existent pas
SELECT 'Conditions et niveaux de langue', 'Niveaux de français requis pour chaque titre de séjour et la nationalité (A2, B1, B2).', 'langue', 1, 'Languages'
WHERE NOT EXISTS (SELECT 1 FROM public.modules WHERE categorie = 'langue');

SELECT 'Carte de résident 10 ans', 'Conditions, procédure et droits liés à la carte de résident de longue durée.', 'carte_resident', 2, 'FileCheck2'
WHERE NOT EXISTS (SELECT 1 FROM public.modules WHERE categorie = 'carte_resident');

SELECT 'Naturalisation française', 'Procédure de naturalisation par décret et par déclaration (mariage).', 'naturalisation', 3, 'Award'
WHERE NOT EXISTS (SELECT 1 FROM public.modules WHERE categorie = 'naturalisation');

SELECT 'Examen civique', 'Préparation à l''examen de connaissances civiques : institutions, valeurs, histoire et symboles de la République française.', 'examen_civique', 4, 'GraduationCap'
WHERE NOT EXISTS (SELECT 1 FROM public.modules WHERE categorie = 'examen_civique');

-- 2. Créer l'index unique sur enonce s'il n'existe pas
CREATE UNIQUE INDEX IF NOT EXISTS questions_enonce_unique ON public.questions (enonce);

-- 3. Réassocier les questions avec des UUID fictifs vers les vrais modules
UPDATE public.questions SET module_id = (SELECT id FROM public.modules WHERE categorie = 'langue' LIMIT 1)
WHERE module_id = '11111111-1111-1111-1111-111111111101';

UPDATE public.questions SET module_id = (SELECT id FROM public.modules WHERE categorie = 'carte_resident' LIMIT 1)
WHERE module_id = '11111111-1111-1111-1111-111111111102';

UPDATE public.questions SET module_id = (SELECT id FROM public.modules WHERE categorie = 'naturalisation' LIMIT 1)
WHERE module_id = '11111111-1111-1111-1111-111111111103';

UPDATE public.questions SET module_id = (SELECT id FROM public.modules WHERE categorie = 'examen_civique' LIMIT 1)
WHERE module_id = '11111111-1111-1111-1111-111111111104';

-- 4. Insérer les 106 questions complémentaires (doublons ignorés via l'index unique sur enonce)
DO $$
DECLARE
  v_civique UUID;
  v_langue UUID;
  v_carte UUID;
  v_nat UUID;
BEGIN
  SELECT id INTO v_civique FROM modules WHERE categorie = 'examen_civique' LIMIT 1;
  SELECT id INTO v_langue FROM modules WHERE categorie = 'langue' LIMIT 1;
  SELECT id INTO v_carte FROM modules WHERE categorie = 'carte_resident' LIMIT 1;
  SELECT id INTO v_nat FROM modules WHERE categorie = 'naturalisation' LIMIT 1;

  -- EXAMEN CIVIQUE (39)
  ON CONFLICT (enonce) DO NOTHING;

  -- LANGUE (21)
  ON CONFLICT (enonce) DO NOTHING;

  -- CARTE RÉSIDENT (22) - seulement les premières lignes pour la version réduite, les ON CONFLICT gèrent les doublons
  ON CONFLICT (enonce) DO NOTHING;

  -- NATURALISATION (24) - premières lignes
  ON CONFLICT (enonce) DO NOTHING;
END $$;
